/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel with:
 * - Template rendering: maps notification metadata to HTML/plain-text templates
 * - Recipient resolution: validates email addresses before sending
 * - Configurable transport: accepts an EmailTransport for actual delivery
 *   (defaults to an in-memory transport for development/testing)
 */

import type { NotificationAdapter, SendResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Record of an email that was sent (or attempted).
 */
export interface SentEmail {
  to: string;
  from: string;
  subject: string;
  bodyText: string;
  bodyHtml: string;
  sentAt: Date;
}

/**
 * Configuration for the EmailAdapter.
 */
export interface EmailAdapterConfig {
  /** Sender address shown in the "From" field. */
  fromAddress: string;
  /** Application name used in templates. */
  appName: string;
}

/**
 * Transport interface — abstracts how emails are actually delivered.
 * Implement this for SES, SendGrid, SMTP, etc.
 */
export interface EmailTransport {
  sendMail(email: SentEmail): Promise<{ success: boolean; errorMessage?: string }>;
}

/**
 * Default in-memory transport: stores emails in an array.
 * Suitable for development and testing.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: SentEmail[] = [];

  async sendMail(email: SentEmail): Promise<{ success: boolean; errorMessage?: string }> {
    this.sent.push(email);
    return { success: true };
  }

  getSentEmails(): SentEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
  }
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Renders the plain-text body for an email from a NotificationPayload.
 * Uses metadata fields (e.g. userName, orderItems) to produce richer content
 * when available, falling back to the payload body.
 */
export function renderTextBody(payload: NotificationPayload, appName: string): string {
  const meta = payload.metadata ?? {};
  const greeting = meta['userName'] ? `Hi ${meta['userName']},` : 'Hello,';
  const footer = `\nThank you,\n${appName} Team`;

  return `${greeting}\n\n${payload.body}${footer}`;
}

/**
 * Renders an HTML body wrapping the text content in minimal markup.
 */
export function renderHtmlBody(payload: NotificationPayload, appName: string): string {
  const meta = payload.metadata ?? {};
  const greeting = meta['userName'] ? `Hi ${meta['userName']},` : 'Hello,';

  const bodyParagraphs = payload.body
    .split('\n')
    .map((line) => `<p>${escapeHtml(line)}</p>`)
    .join('\n    ');

  return `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: sans-serif; color: #333;">
  <div style="max-width: 600px; margin: 0 auto; padding: 20px;">
    <p>${escapeHtml(greeting)}</p>
    ${bodyParagraphs}
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="font-size: 12px; color: #999;">Thank you,<br>${escapeHtml(appName)} Team</p>
  </div>
</body>
</html>`;
}

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Validates that a recipient string looks like a valid email address.
 */
export function isValidEmail(email: string): boolean {
  return EMAIL_REGEX.test(email);
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private transport: EmailTransport;
  private config: EmailAdapterConfig;

  constructor(
    config?: Partial<EmailAdapterConfig>,
    transport?: EmailTransport,
  ) {
    this.config = {
      fromAddress: config?.fromAddress ?? 'noreply@taskflowpro.com',
      appName: config?.appName ?? 'TaskFlow Pro',
    };
    this.transport = transport ?? new InMemoryTransport();
  }

  /**
   * Send an email notification.
   *
   * 1. Validates the recipient address
   * 2. Renders text and HTML bodies from the payload + templates
   * 3. Delegates to the configured transport
   *
   * Never throws — returns SendResult with success: false on failure.
   */
  async send(payload: NotificationPayload): Promise<SendResult> {
    try {
      if (!payload.recipient || !isValidEmail(payload.recipient)) {
        this.logger.warn(`Invalid recipient email: ${payload.recipient}`);
        return { success: false, errorMessage: `Invalid recipient email: ${payload.recipient}` };
      }

      const bodyText = renderTextBody(payload, this.config.appName);
      const bodyHtml = renderHtmlBody(payload, this.config.appName);

      const email: SentEmail = {
        to: payload.recipient,
        from: this.config.fromAddress,
        subject: payload.subject,
        bodyText,
        bodyHtml,
        sentAt: new Date(),
      };

      this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

      const result = await this.transport.sendMail(email);
      if (!result.success) {
        this.logger.error(`Transport failed for ${payload.recipient}: ${result.errorMessage ?? 'unknown'}`);
        return { success: false, errorMessage: result.errorMessage };
      }

      return { success: true };
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Unexpected error sending email: ${message}`);
      return { success: false, errorMessage: message };
    }
  }

  /**
   * Get sent emails (only works with InMemoryTransport).
   */
  getSentEmails(): SentEmail[] {
    if (this.transport instanceof InMemoryTransport) {
      return this.transport.getSentEmails();
    }
    return [];
  }

  /**
   * Clear sent emails (only works with InMemoryTransport).
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryTransport) {
      this.transport.clear();
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
  renderTextBody,
  renderHtmlBody,
  isValidEmail,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport, SentEmail } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content.',
    channel: 'email',
    priority: 'normal',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let transport: InMemoryTransport;
  let adapter: EmailAdapter;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter(
      { fromAddress: 'noreply@test.com', appName: 'TestApp' },
      transport,
    );
  });

  describe('send', () => {
    it('should send an email through the transport', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = transport.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@test.com');
      expect(sent[0]?.subject).toBe('Test Subject');
    });

    it('should render text and HTML bodies', async () => {
      await adapter.send(makePayload({ metadata: { userName: 'Alice' } }));

      const sent = transport.getSentEmails();
      expect(sent[0]?.bodyText).toContain('Hi Alice,');
      expect(sent[0]?.bodyText).toContain('Test body content.');
      expect(sent[0]?.bodyText).toContain('TestApp Team');
      expect(sent[0]?.bodyHtml).toContain('Hi Alice,');
      expect(sent[0]?.bodyHtml).toContain('Test body content.');
      expect(sent[0]?.bodyHtml).toContain('TestApp Team');
    });

    it('should reject invalid email addresses', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid recipient email');
      expect(transport.getSentEmails()).toHaveLength(0);
    });

    it('should reject empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('Invalid recipient email');
    });

    it('should handle transport failures gracefully', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          return { success: false, errorMessage: 'SMTP connection refused' };
        },
      };
      const failAdapter = new EmailAdapter({}, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('SMTP connection refused');
    });

    it('should catch transport exceptions and return SendResult', async () => {
      const throwingTransport: EmailTransport = {
        async sendMail() {
          throw new Error('Network timeout');
        },
      };
      const throwAdapter = new EmailAdapter({}, throwingTransport);

      const result = await throwAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.errorMessage).toBe('Network timeout');
    });

    it('should use default config when none provided', async () => {
      const defaultAdapter = new EmailAdapter(undefined, transport);
      await defaultAdapter.send(makePayload());

      const sent = transport.getSentEmails();
      expect(sent[0]?.from).toBe('noreply@taskflowpro.com');
      expect(sent[0]?.bodyText).toContain('TaskFlow Pro Team');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return sent emails from in-memory transport', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      adapter.clearSentEmails();

      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return empty array for non-InMemoryTransport', () => {
      const customAdapter = new EmailAdapter({}, {
        async sendMail() { return { success: true }; },
      });
      expect(customAdapter.getSentEmails()).toEqual([]);
    });
  });
});

describe('isValidEmail', () => {
  it('should accept valid emails', () => {
    expect(isValidEmail('user@example.com')).toBe(true);
    expect(isValidEmail('a.b+c@domain.co.uk')).toBe(true);
  });

  it('should reject invalid emails', () => {
    expect(isValidEmail('')).toBe(false);
    expect(isValidEmail('not-an-email')).toBe(false);
    expect(isValidEmail('@missing-local.com')).toBe(false);
    expect(isValidEmail('missing@')).toBe(false);
    expect(isValidEmail('has spaces@example.com')).toBe(false);
  });
});

describe('renderTextBody', () => {
  it('should use userName from metadata when available', () => {
    const payload = makePayload({ metadata: { userName: 'Bob' } });
    const text = renderTextBody(payload, 'MyApp');

    expect(text).toContain('Hi Bob,');
    expect(text).toContain('Test body content.');
    expect(text).toContain('MyApp Team');
  });

  it('should fall back to generic greeting without userName', () => {
    const text = renderTextBody(makePayload(), 'MyApp');
    expect(text).toContain('Hello,');
  });
});

describe('renderHtmlBody', () => {
  it('should produce valid HTML with escaped content', () => {
    const payload = makePayload({
      body: 'Items: <script>alert("xss")</script>',
      metadata: { userName: 'Alice' },
    });
    const html = renderHtmlBody(payload, 'MyApp');

    expect(html).toContain('<!DOCTYPE html>');
    expect(html).toContain('Hi Alice,');
    expect(html).toContain('&lt;script&gt;');
    expect(html).not.toContain('<script>');
    expect(html).toContain('MyApp Team');
  });

  it('should wrap each line in a paragraph', () => {
    const payload = makePayload({ body: 'Line one.\nLine two.' });
    const html = renderHtmlBody(payload, 'App');

    expect(html).toContain('<p>Line one.</p>');
    expect(html).toContain('<p>Line two.</p>');
  });
});

